public class MsckDesc extends DDLWork implements Serializable { private String tableName ; private ArrayList < LinkedHashMap < String , String > > partSpecs ; private String resFile ; private boolean repairPartitions ; public MsckDesc ( ) { } public MsckDesc ( String tableName , List < ? extends Map < String , String > > partSpecs , Path resFile , boolean repairPartitions ) { super ( ) ; this . tableName = tableName ; this . partSpecs = new ArrayList < LinkedHashMap < String , String > > ( partSpecs . size ( ) ) ; for ( int i = 0 ; i < partSpecs . size ( ) ; i ++ ) { this . partSpecs . add ( new LinkedHashMap < String , String > ( partSpecs . get ( i ) ) ) ; } this . resFile = resFile . toString ( ) ; this . repairPartitions = repairPartitions ; } public String getTableName ( ) { return tableName ; } public void setTableName ( String tableName ) { this . tableName = tableName ; } public ArrayList < LinkedHashMap < String , String > > getPartSpecs ( ) { return partSpecs ; } public void setPartSpecs ( ArrayList < LinkedHashMap < String , String > > partSpecs ) { this . partSpecs = partSpecs ; } public String getResFile ( ) { return resFile ; } public void setResFile ( String resFile ) { this . resFile = resFile ; } public boolean isRepairPartitions ( ) { return repairPartitions ; } public void setRepairPartitions ( boolean repairPartitions ) { this . repairPartitions = repairPartitions ; } }